import React from "react";
import "./nav.css";

function Nav() {
  const [isActive, setIsActive] = React.useState(false);
  const handleClick = () => {
    setIsActive((current) => !current);
  };
  return (
    <div>
      <div
        value={isActive}
        className="pushMenu"
        onChange={(e) =>
          ({
            display: isActive ? "block" : "",
            color: isActive ? "none" : "",
          }(e.target.value))
        }
      ></div>
      <div onClick={handleClick} className="gg-menu-grid-o"></div>
    </div>
  );
}

export default Nav;

